import numpy as np

class LayerNorm:
    def __init__(self, d_model: int, eps: float = 1e-5):
        self.d_model = d_model
        self.eps = eps
        self.gamma = np.ones(d_model)   # scale
        self.beta = np.zeros(d_model)   # shift

    def forward(self, x: np.ndarray) -> np.ndarray:
        # Normalize over the last dimension
        mu = x.mean(axis=-1, keepdims=True)             # (..., 1)
        var = x.var(axis=-1, keepdims=True)              # (..., 1)
        x_norm = (x - mu) / np.sqrt(var + self.eps)     # (..., d_model)
        return self.gamma * x_norm + self.beta           # (..., d_model)
